def Transform(extractedData, standardDataclass):
    import ast
    data = ast.literal_eval(extractedData)
    data_block = data.get('DATA', {})
    if 'VALUES' in data_block:
        standardDataclass.values = list(data_block['VALUES'])
        standardDataclass.length = len(data_block['VALUES'])
    if 'WEIGHTS' in data_block:
        standardDataclass.weights = list(data_block['WEIGHTS'])
    if 'CAPACITY' in data_block:
        standardDataclass.capacity = data_block['CAPACITY']
    if 'SOLUTION' in data:
        standardDataclass.solution = list(data['SOLUTION'])
        try:
            vals = data_block.get('VALUES', [])
            standardDataclass.score = sum(vals[i] for i in data['SOLUTION'])
        except Exception:
            pass
    return standardDataclass
